    private OkHttpClient buildCloudClient(IoTClientConfig config) {
        OkHttpClient.Builder builder = new OkHttpClient.Builder()
                .connectTimeout(config.cloudConnectTimeout, TimeUnit.SECONDS)
                .readTimeout(config.cloudReadTimeout, TimeUnit.SECONDS)
                .writeTimeout(config.cloudWriteTimeout, TimeUnit.SECONDS)
                .connectionPool(new ConnectionPool(
                        config.maxIdleConnections,
                        config.keepAliveDuration,
                        TimeUnit.MINUTES))
                .cache(new Cache(context.getCacheDir(), config.cacheSize))
                .addInterceptor(new AuthInterceptor())
                .addInterceptor(new RetryInterceptor(config.maxRetries, config.retryDelayMs))
                .addInterceptor(new NetworkCheckInterceptor());

        // Certificate pinning for cloud
        if (config.certificatePinHosts.length > 0 && config.certificatePinSha256.length > 0) {
            CertificatePinner.Builder pinnerBuilder = new CertificatePinner.Builder();
            for (String host : config.certificatePinHosts) {
                for (String pin : config.certificatePinSha256) {
                    pinnerBuilder.add(host, "sha256/" + pin);
                }
            }
            builder.certificatePinner(pinnerBuilder.build());
        }

        if (config.enableLogging) {
            HttpLoggingInterceptor loggingInterceptor = new HttpLoggingInterceptor(
                    message -> Log.d(TAG, "[Cloud] " + message));
            loggingInterceptor.setLevel(HttpLoggingInterceptor.Level.BODY);
            builder.addInterceptor(loggingInterceptor);
        }

        return builder.build();
    }

    private OkHttpClient buildLocalClient(IoTClientConfig config) {
        OkHttpClient.Builder builder = new OkHttpClient.Builder()
                .connectTimeout(config.localConnectTimeout, TimeUnit.SECONDS)
                .readTimeout(config.localReadTimeout, TimeUnit.SECONDS)
                .writeTimeout(config.localWriteTimeout, TimeUnit.SECONDS)
                .connectionPool(new ConnectionPool(20, 2, TimeUnit.MINUTES))
                .addInterceptor(new RetryInterceptor(2, 500))
                .retryOnConnectionFailure(true);

        // For local network devices, we may need to trust self-signed certificates
        if (config.trustLocalCertificates) {
            try {
                X509TrustManager trustManager = new X509TrustManager() {
                    @Override
                    public void checkClientTrusted(X509Certificate[] chain, String authType) {}

                    @Override
                    public void checkServerTrusted(X509Certificate[] chain, String authType) {}

                    @Override
                    public X509Certificate[] getAcceptedIssuers() {
                        return new X509Certificate[0];
                    }
                };

                SSLContext sslContext = SSLContext.getInstance("TLS");
                sslContext.init(null, new TrustManager[]{trustManager}, new SecureRandom());
                SSLSocketFactory sslSocketFactory = sslContext.getSocketFactory();

                builder.sslSocketFactory(sslSocketFactory, trustManager);
                builder.hostnameVerifier((hostname, session) -> {
                    // Only trust local network addresses
                    return isLocalNetworkAddress(hostname);
                });
            } catch (NoSuchAlgorithmException | KeyManagementException e) {
                Log.e(TAG, "Failed to configure local SSL trust", e);
            }
        }

        if (config.enableLogging) {
            HttpLoggingInterceptor loggingInterceptor = new HttpLoggingInterceptor(
                    message -> Log.d(TAG, "[Local] " + message));
            loggingInterceptor.setLevel(HttpLoggingInterceptor.Level.BODY);
            builder.addInterceptor(loggingInterceptor);
        }

        return builder.build();
    }

