    private class AuthInterceptor implements Interceptor {
        @Override
        public Response intercept(Chain chain) throws IOException {
            Request original = chain.request();

            if (authToken == null || authToken.isEmpty()) {
                return chain.proceed(original);
            }

            Request.Builder builder = original.newBuilder()
                    .header("Authorization", "Bearer " + authToken)
                    .header("Content-Type", "application/json")
                    .header("Accept", "application/json")
                    .header("X-Client-Platform", "Android")
                    .header("X-Client-Version", "1.0.0");

            return chain.proceed(builder.build());
        }
    }

    private class RetryInterceptor implements Interceptor {
        private final int maxRetries;
        private final long retryDelayMs;

        RetryInterceptor(int maxRetries, long retryDelayMs) {
            this.maxRetries = maxRetries;
            this.retryDelayMs = retryDelayMs;
        }

        @Override
        public Response intercept(Chain chain) throws IOException {
            Request request = chain.request();
            IOException lastException = null;

            for (int attempt = 0; attempt <= maxRetries; attempt++) {
                try {
                    Response response = chain.proceed(request);

                    // Don't retry on client errors (4xx)
                    if (response.isSuccessful() || (response.code() >= 400 && response.code() < 500)) {
                        return response;
                    }

                    // Retry on server errors (5xx)
                    if (attempt < maxRetries) {
                        response.close();
                        Log.w(TAG, "Request failed with " + response.code() +
                                ", retrying (" + (attempt + 1) + "/" + maxRetries + ")");
                        sleep(retryDelayMs * (attempt + 1)); // Exponential-ish backoff
                    } else {
                        return response;
                    }
                } catch (IOException e) {
                    lastException = e;
                    if (attempt < maxRetries) {
                        Log.w(TAG, "Request failed with IOException, retrying (" +
                                (attempt + 1) + "/" + maxRetries + "): " + e.getMessage());
                        sleep(retryDelayMs * (attempt + 1));
                    }
                }
            }

            throw lastException != null ? lastException : new IOException("Request failed after retries");
        }

        private void sleep(long ms) {
            try {
                Thread.sleep(ms);
            } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
            }
        }
    }

    private class NetworkCheckInterceptor implements Interceptor {
        @Override
        public Response intercept(Chain chain) throws IOException {
            if (!isNetworkAvailable()) {
                throw new IOException("No network connection available");
            }
            return chain.proceed(chain.request());
        }
    }

