    /**
     * Discover a device at a specific IP address
     */
    public IoTResponse<DeviceInfo> discoverDevice(String ip, int port, boolean useHttps) {
        return localGet(ip, port, useHttps, "/device/info", DeviceInfo.class);
    }

    /**
     * Discover devices across a subnet asynchronously
     */
    public void discoverDevicesOnSubnet(String subnetPrefix, int port,
                                         DeviceDiscoveryCallback callback) {
        new Thread(() -> {
            int found = 0;
            for (int i = 1; i < 255; i++) {
                String ip = subnetPrefix + "." + i;
                try {
                    InetAddress address = InetAddress.getByName(ip);
                    if (address.isReachable(500)) {
                        // Try HTTPS first, fall back to HTTP
                        IoTResponse<DeviceInfo> response = discoverDevice(ip, port, true);
                        if (!response.isSuccess()) {
                            response = discoverDevice(ip, port, false);
                        }

                        if (response.isSuccess() && response.getData() != null) {
                            DeviceInfo info = response.getData();
                            info.ipAddress = ip;
                            info.port = port;
                            callback.onDeviceFound(ip, info);
                            found++;
                        }
                    }
                } catch (Exception e) {
                    // Skip unreachable hosts
                }
            }
            callback.onDiscoveryComplete(found);
        }, "device-discovery").start();
    }

